/* Lightweight local Chart.js-compatible fallback for offline MVP demos.
   It implements the small API surface this project needs: new Chart(ctx, config). */
(function () {
  function valuesFromConfig(config) {
    var data = (config && config.data) || {};
    var labels = data.labels || [];
    var datasets = data.datasets || [];
    var first = datasets[0] || {};
    var values = first.data || [];
    if (!labels.length && data && !Array.isArray(data) && typeof data === 'object') {
      labels = Object.keys(data);
      values = labels.map(function (key) { return data[key]; });
    }
    return { labels: labels, values: values.map(function (v) { var n = Number(v); return isFinite(n) ? n : 0; }) };
  }
  function clear(ctx, canvas) {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }
  function text(ctx, value, x, y, size, weight) {
    ctx.fillStyle = '#344054';
    ctx.font = (weight || '400') + ' ' + (size || 12) + 'px Arial, sans-serif';
    ctx.fillText(String(value), x, y);
  }
  function drawBars(ctx, canvas, labels, values, horizontal) {
    var w = canvas.width, h = canvas.height, pad = 38;
    var max = Math.max.apply(null, values.concat([1]));
    ctx.strokeStyle = '#d0d5dd';
    ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(pad, pad / 2); ctx.lineTo(pad, h - pad); ctx.lineTo(w - 12, h - pad); ctx.stroke();
    if (horizontal) {
      var row = (h - pad * 1.2) / Math.max(labels.length, 1);
      labels.forEach(function (label, i) {
        var y = pad / 2 + i * row + row * 0.25;
        var bw = (w - pad * 2.4) * (values[i] / max);
        ctx.fillStyle = '#2a5298'; ctx.fillRect(pad + 95, y, Math.max(2, bw), Math.max(8, row * 0.38));
        text(ctx, label, pad, y + 12, 11, '600'); text(ctx, values[i], pad + 100 + bw, y + 12, 11, '400');
      });
    } else {
      var slot = (w - pad * 1.5) / Math.max(labels.length, 1);
      labels.forEach(function (label, i) {
        var bh = (h - pad * 1.7) * (values[i] / max);
        var x = pad + i * slot + slot * 0.2;
        var y = h - pad - bh;
        ctx.fillStyle = '#2a5298'; ctx.fillRect(x, y, Math.max(10, slot * 0.55), bh);
        text(ctx, label, x, h - 12, 10, '600'); text(ctx, values[i], x, y - 6, 10, '400');
      });
    }
  }
  function drawLine(ctx, canvas, labels, values) {
    var w = canvas.width, h = canvas.height, pad = 38;
    var max = Math.max.apply(null, values.concat([1]));
    ctx.strokeStyle = '#d0d5dd'; ctx.beginPath(); ctx.moveTo(pad, pad / 2); ctx.lineTo(pad, h - pad); ctx.lineTo(w - 12, h - pad); ctx.stroke();
    ctx.strokeStyle = '#2a5298'; ctx.lineWidth = 3; ctx.beginPath();
    values.forEach(function (v, i) {
      var x = pad + (w - pad * 1.5) * (i / Math.max(values.length - 1, 1));
      var y = h - pad - (h - pad * 1.7) * (v / max);
      if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    });
    ctx.stroke();
    values.forEach(function (v, i) {
      var x = pad + (w - pad * 1.5) * (i / Math.max(values.length - 1, 1));
      var y = h - pad - (h - pad * 1.7) * (v / max);
      ctx.fillStyle = '#2a5298'; ctx.beginPath(); ctx.arc(x, y, 4, 0, Math.PI * 2); ctx.fill();
      text(ctx, labels[i] || '', x - 14, h - 12, 10, '600');
    });
  }
  function drawPie(ctx, canvas, labels, values) {
    var total = values.reduce(function (a, b) { return a + b; }, 0) || 1;
    var cx = canvas.width / 2, cy = canvas.height / 2, r = Math.min(cx, cy) - 28;
    var start = -Math.PI / 2;
    var palette = ['#2a5298', '#49C8C0', '#FFCD00', '#E73C3E', '#8E7CC3', '#6AA84F'];
    values.forEach(function (v, i) {
      var end = start + Math.PI * 2 * (v / total);
      ctx.fillStyle = palette[i % palette.length]; ctx.beginPath(); ctx.moveTo(cx, cy); ctx.arc(cx, cy, r, start, end); ctx.closePath(); ctx.fill();
      start = end;
    });
    labels.forEach(function (label, i) { text(ctx, label + ': ' + values[i], 12, 18 + i * 16, 11, '600'); });
  }
  function Chart(ctx, config) {
    var canvas = ctx && ctx.canvas ? ctx.canvas : ctx;
    if (!canvas || !canvas.getContext) return this;
    var context = canvas.getContext('2d');
    var rect = canvas.getBoundingClientRect ? canvas.getBoundingClientRect() : { width: 760, height: 260 };
    canvas.width = canvas.width || Math.max(480, Math.floor(rect.width || 760));
    canvas.height = canvas.height || Number(canvas.getAttribute('height')) || 260;
    clear(context, canvas);
    var pack = valuesFromConfig(config);
    var type = (config && config.type) || 'bar';
    if (type === 'pie' || type === 'doughnut') drawPie(context, canvas, pack.labels, pack.values);
    else if (type === 'line') drawLine(context, canvas, pack.labels, pack.values);
    else drawBars(context, canvas, pack.labels, pack.values, config && config.options && config.options.indexAxis === 'y');
    this.destroy = function () { clear(context, canvas); };
    this.update = function () {};
    return this;
  }
  window.Chart = window.Chart || Chart;
})();
